import React, { useEffect, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './XacThucDanhTinh.css';

const MAX_FILE_SIZE = 10 * 1024 * 1024;
const MAX_UPLOAD_IMAGE_DIMENSION = 1800;
const JPEG_QUALITY = 0.9;

const createObjectUrl = file => URL.createObjectURL(file);

const loadImage = file => new Promise((resolve, reject) => {
  const previewUrl = createObjectUrl(file);
  const image = new Image();

  image.onload = () => {
    URL.revokeObjectURL(previewUrl);
    resolve(image);
  };

  image.onerror = () => {
    URL.revokeObjectURL(previewUrl);
    reject(new Error('Khong doc duoc anh da chon.'));
  };

  image.src = previewUrl;
});

const optimizeImageForUpload = async file => {
  const image = await loadImage(file);
  const shouldRotate = image.height > image.width;
  const sourceWidth = shouldRotate ? image.height : image.width;
  const sourceHeight = shouldRotate ? image.width : image.height;
  const maxDimension = Math.max(sourceWidth, sourceHeight);
  const scale = maxDimension > MAX_UPLOAD_IMAGE_DIMENSION
    ? MAX_UPLOAD_IMAGE_DIMENSION / maxDimension
    : 1;

  const canvas = document.createElement('canvas');
  canvas.width = Math.max(1, Math.round(sourceWidth * scale));
  canvas.height = Math.max(1, Math.round(sourceHeight * scale));

  const context = canvas.getContext('2d');
  context.imageSmoothingEnabled = true;
  context.imageSmoothingQuality = 'high';

  if (shouldRotate) {
    context.translate(canvas.width / 2, canvas.height / 2);
    context.rotate(Math.PI / 2);
    context.drawImage(
      image,
      -canvas.height / 2,
      -canvas.width / 2,
      canvas.height,
      canvas.width
    );
  } else {
    context.drawImage(image, 0, 0, canvas.width, canvas.height);
  }

  const blob = await new Promise(resolve => {
    canvas.toBlob(resolve, 'image/jpeg', JPEG_QUALITY);
  });

  if (!blob) {
    return file;
  }

  const fileName = file.name.replace(/\.[^.]+$/, '') || 'cccd';
  return new File([blob], `${fileName}.jpg`, {
    type: 'image/jpeg',
    lastModified: Date.now(),
  });
};

const getErrorMessage = error => {
  if (error.code === 'ECONNABORTED' || String(error.message || '').toLowerCase().includes('timeout')) {
    return 'Qua trinh OCR mat qua nhieu thoi gian. Hay chup lai anh ro hon, can the nam ngang, du sang va khong bi loa.';
  }

  if (!error.response) {
    return 'Khong the ket noi den may chu xac thuc. Vui long kiem tra backend dang chay roi thu lai.';
  }

  if (error.response?.data?.message) {
    const message = error.response.data.message;
    const normalized = message.toLowerCase();

    if (normalized.includes('app.cccd.ocr.tessdata-path')) {
      return message;
    }
    if (normalized.includes('tessdata') || normalized.includes('traineddata')) {
      return 'Backend chua cau hinh Tesseract OCR hoac thieu vie.traineddata nen chua the xac thuc CCCD.';
    }

    return message;
  }

  return error.message || 'Xac thuc that bai';
};

const sideContent = {
  truoc: {
    inputId: 'mat-truoc',
    title: 'Mat truoc',
    previewAlt: 'Mat truoc CCCD',
    helper: 'So CCCD va ho ten phai ro',
  },
  sau: {
    inputId: 'mat-sau',
    title: 'Mat sau',
    previewAlt: 'Mat sau CCCD',
    helper: 'Dia chi va dac diem nhan dang phai ro',
  },
};

export default function XacThucDanhTinh() {
  const { layThongTinToi } = useAuthStore();
  const navigate = useNavigate();
  const fileInputRefs = useRef({});
  const [matTruoc, setMatTruoc] = useState(null);
  const [matSau, setMatSau] = useState(null);
  const [prevTruoc, setPrevTruoc] = useState(null);
  const [prevSau, setPrevSau] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [verificationError, setVerificationError] = useState('');

  useEffect(() => () => {
    if (prevTruoc) URL.revokeObjectURL(prevTruoc);
    if (prevSau) URL.revokeObjectURL(prevSau);
  }, [prevTruoc, prevSau]);

  const clearResult = () => {
    setResult(null);
    setVerificationError('');
  };

  const clearImage = side => {
    clearResult();

    if (side === 'truoc') {
      if (prevTruoc) URL.revokeObjectURL(prevTruoc);
      setMatTruoc(null);
      setPrevTruoc(null);
    } else {
      if (prevSau) URL.revokeObjectURL(prevSau);
      setMatSau(null);
      setPrevSau(null);
    }

    const input = fileInputRefs.current[side];
    if (input) {
      input.value = '';
    }
  };

  const handleFile = async (side, file) => {
    if (!file) {
      return;
    }

    clearResult();

    if (!file.type.startsWith('image/')) {
      setVerificationError('Chi chap nhan file anh.');
      return;
    }

    if (file.size > MAX_FILE_SIZE) {
      setVerificationError('Anh vuot qua 10MB. Vui long chon anh nhe hon.');
      return;
    }

    try {
      const optimizedFile = await optimizeImageForUpload(file);
      const nextPreview = createObjectUrl(optimizedFile);

      if (side === 'truoc') {
        if (prevTruoc) URL.revokeObjectURL(prevTruoc);
        setMatTruoc(optimizedFile);
        setPrevTruoc(nextPreview);
        return;
      }

      if (prevSau) URL.revokeObjectURL(prevSau);
      setMatSau(optimizedFile);
      setPrevSau(nextPreview);
    } catch (error) {
      setVerificationError(error.message || 'Khong xu ly duoc anh da chon.');
    }
  };

  const handleSubmit = async e => {
    e.preventDefault();

    if (!matTruoc || !matSau) {
      setVerificationError('Vui long chon ca hai mat CCCD/CMND truoc khi xac thuc.');
      return;
    }

    setLoading(true);
    clearResult();

    try {
      const fd = new FormData();
      fd.append('matTruoc', matTruoc);
      fd.append('matSau', matSau);

      const res = await nguoiDungAPI.xacThucCCCD(fd);
      const verificationResult = res.data?.data;

      if (verificationResult?.xacThucThanhCong !== true) {
        throw new Error(res.data?.message || 'Xac thuc that bai');
      }

      setResult({ xacThucThanhCong: true });
      await layThongTinToi();
      toast.success(verificationResult?.thongBao || 'Xac thuc danh tinh thanh cong');
    } catch (error) {
      setResult(null);
      setVerificationError(getErrorMessage(error));
    } finally {
      setLoading(false);
    }
  };

  const isVerified = result?.xacThucThanhCong === true;

  const renderUploadCard = side => {
    const config = sideContent[side];
    const preview = side === 'truoc' ? prevTruoc : prevSau;
    const hasImage = Boolean(preview);

    return (
      <div className="cccd-upload-box">
        <label htmlFor={config.inputId} className={`upload-label${hasImage ? ' has-image' : ''}`}>
          {hasImage ? (
            <img src={preview} alt={config.previewAlt} />
          ) : (
            <div className="upload-placeholder">
              <span className="upload-placeholder-icon">ID</span>
              <p>{config.title}</p>
              <small>Chon anh hoac mo camera</small>
            </div>
          )}
        </label>
        <input
          id={config.inputId}
          ref={node => {
            fileInputRefs.current[side] = node;
          }}
          type="file"
          accept="image/*"
          capture="environment"
          hidden
          onChange={e => handleFile(side, e.target.files?.[0])}
        />
        <div className="upload-meta">
          <p className="upload-label-text">{config.title}</p>
          <span className="upload-helper-text">{config.helper}</span>
        </div>
        <div className="upload-actions">
          <button
            type="button"
            className="btn btn-secondary"
            onClick={() => fileInputRefs.current[side]?.click()}
            disabled={loading}
          >
            {hasImage ? 'Chon lai' : 'Tai anh'}
          </button>
          {hasImage && (
            <button
              type="button"
              className="btn btn-ghost"
              onClick={() => clearImage(side)}
              disabled={loading}
            >
              Xoa anh
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="container page-wrapper">
      <div className="xacthuc-wrapper">
        <div className="card">
          <div className="card-body">
            <div className="xacthuc-hero">
              <div className="xacthuc-badge">Xac thuc CCCD</div>
              <h1>Xac thuc danh tinh</h1>
              <p>
                Trang nay da duoc sua de de quet hon tren dien thoai: co the mo camera sau,
                tu dong xoay anh ve ngang va nen anh truoc khi gui OCR.
              </p>
            </div>

            <div className="alert alert-info">
              Chi tai khoan da xac thuc moi co the <strong>dang phong</strong>, <strong>apply vao phong</strong> va <strong>thanh toan</strong>.
            </div>

            <div className="xacthuc-tips-strip">
              <span>1. Dat the nam ngang</span>
              <span>2. Lay tron 4 goc</span>
              <span>3. Khong dung anh bi loa</span>
            </div>

            {verificationError && (
              <div className="xacthuc-message xacthuc-message-error" role="alert">
                <strong>Xac thuc chua thanh cong</strong>
                <span>{verificationError}</span>
              </div>
            )}

            {isVerified ? (
              <div className="xacthuc-result">
                <div className="result-icon">OK</div>
                <h2>Xac thuc thanh cong!</h2>
                <button className="btn btn-primary btn-lg" style={{ marginTop: 20 }} onClick={() => navigate('/')}>
                  Ve trang chu
                </button>
              </div>
            ) : (
              <form onSubmit={handleSubmit}>
                <div className="grid-2 verification-grid">
                  {renderUploadCard('truoc')}
                  {renderUploadCard('sau')}
                </div>

                <div className="xacthuc-actions">
                  <button type="submit" className="btn btn-primary btn-block btn-lg" disabled={loading}>
                    {loading ? 'Dang xu ly anh va xac thuc...' : 'Xac thuc ngay'}
                  </button>
                  <p className="upload-submit-note">
                    Neu OCR van kho doc, hay chup sat hon mot chut, giu may song song voi the va tranh bong den.
                  </p>
                </div>
              </form>
            )}
          </div>
        </div>

        <div className="card" style={{ marginTop: 20 }}>
          <div className="card-body">
            <h3 style={{ marginBottom: 12 }}>Huong dan chup anh</h3>
            <ul className="xacthuc-guide-list">
              <li>Dat CCCD tren nen toi mau hoac nen don sac de the noi bat.</li>
              <li>Chup bang camera sau neu co the, vi thuong net hon camera truoc.</li>
              <li>Can the nam ngang, chup thang tu tren xuong, tranh nghieng va xoay lech.</li>
              <li>Hay chup lai neu so CCCD, ngay sinh hoac dia chi chua doc ro trong anh preview.</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}
